const setup = $('⚙️ Setup').first().json;
const orders = ($json.orders || []).filter(o => !o.cancelled_at);

let umsatz = 0;
let retourenWert = 0;
const produkte = {};
let waehrung = 'EUR';

for (const o of orders) {
  umsatz += parseFloat(o.total_price || 0);
  waehrung = o.currency || waehrung;
  for (const r of (o.refunds || [])) {
    for (const t of (r.transactions || [])) retourenWert += parseFloat(t.amount || 0);
  }
  for (const li of (o.line_items || [])) {
    produkte[li.title] = (produkte[li.title] || 0) + li.quantity;
  }
}

const anzahl = orders.length;
const aov = anzahl ? (umsatz / anzahl) : 0;
const top = Object.entries(produkte).sort((a, b) => b[1] - a[1]).slice(0, 5)
  .map(([name, menge], i) => (i + 1) + '. ' + name + ' (' + menge + 'x)').join('\n');

const werbekosten = parseFloat(setup.WERBEKOSTEN_PRO_TAG || 0);
const produktkosten = umsatz * (parseFloat(setup.PRODUKTKOSTEN_PROZENT || 0) / 100);
const geschaetzterGewinn = umsatz - retourenWert - werbekosten - produktkosten;

const zahlen = 'Umsatz: ' + umsatz.toFixed(2) + ' ' + waehrung + '\n' +
  'Bestellungen: ' + anzahl + '\n' +
  'Durchschnittlicher Bestellwert: ' + aov.toFixed(2) + ' ' + waehrung + '\n' +
  'Erstattungen: ' + retourenWert.toFixed(2) + ' ' + waehrung + '\n' +
  'Werbekosten (dein Wert): ' + werbekosten.toFixed(2) + ' ' + waehrung + '\n' +
  'Geschaetzter Gewinn: ' + geschaetzterGewinn.toFixed(2) + ' ' + waehrung + '\n\n' +
  'Top-Produkte:\n' + (top || 'keine Verkaeufe');

const prompt = 'Du bist E-Commerce-Berater fuer den Shop "' + setup.SHOP_NAME + '".\n' +
  'Hier die Zahlen von gestern:\n\n' + zahlen + '\n\n' +
  'Gib genau 3 kurze, KONKRETE Handlungsempfehlungen fuer heute (jeweils 1-2 Saetze, direkt umsetzbar, keine Floskeln). Nummeriert 1-3, auf Deutsch, Du-Form. Antworte nur mit den 3 Punkten.';

return [{ json: { zahlen, prompt } }];

const blocks = $json.content || [];
const tipps = (blocks.find(b => b.type === 'text') || {}).text || '';
const zahlen = $('🧮 Zahlen berechnen').item.json.zahlen;
const setup = $('⚙️ Setup').first().json;

const telegram_text = '📊 GEWINN-RADAR · ' + setup.SHOP_NAME + '\n' +
  'Gestern:\n\n' + zahlen + '\n\n💡 Deine 3 Moves fuer heute:\n' + tipps;

return { json: { telegram_text } };
